/*
  # Pulizia completa attività utenti test v3

  Elimina tutte le attività degli utenti test in ordine corretto per rispettare
  i vincoli FK. La tabella si chiama activity_log (senza s).
*/

-- 1. Review responses
DELETE FROM review_responses
WHERE review_id IN (
  SELECT id FROM reviews
  WHERE customer_id IN (
    'a1000001-0000-0000-0000-000000000001',
    'a1000002-0000-0000-0000-000000000002'
  )
);

-- 2. Azzera user_activity prima di cancellare (evita trigger di sottrazione punti negativi)
UPDATE user_activity
SET
  total_points = 0,
  reviews_count = 0,
  businesses_added_count = 0,
  ads_posted_count = 0,
  ads_count = 0,
  job_postings_count = 0,
  auctions_count = 0,
  photos_count = 0
WHERE user_id IN (
  'a1000001-0000-0000-0000-000000000001',
  'a1000002-0000-0000-0000-000000000002',
  'b2000001-0000-0000-0000-000000000001',
  'b2000002-0000-0000-0000-000000000002',
  'b2000003-0000-0000-0000-000000000003'
);

-- 3. Reviews
DELETE FROM reviews
WHERE customer_id IN (
  'a1000001-0000-0000-0000-000000000001',
  'a1000002-0000-0000-0000-000000000002'
);

